func lengthOfLongestSubstring(s string) int {
	maxLength := 0
	n := len(s)

	for i := 0; i < n; i++ {
		for j := i + 1; j <= n; j++ {
			substring := s[i:j]
			charSet := make(map[rune]bool)
			isUnique := true

			for _, char := range substring {
				if charSet[char] {
					isUnique = false
					break
				}
				charSet[char] = true
			}

			if isUnique {
				if j-i > maxLength {
					maxLength = j - i
				}
			}
		}
	}

	return maxLength
}

